import{_ as t,c as o,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Project Init: Build AI Memory | opencode-supermemory","description":"Learn to build cross-session AI memory with /supermemory-init. Auto-scan codebase to extract architecture, tech stack, and coding conventions.","frontmatter":{"title":"Project Init: Build AI Memory | opencode-supermemory","sidebarTitle":"Project Init","subtitle":"Project Initialization: Making a First Impression","description":"Learn to build cross-session AI memory with /supermemory-init. Auto-scan codebase to extract architecture, tech stack, and coding conventions.","tags":["Initialization","Memory Generation","Workflow"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"supermemoryai/opencode-supermemory/start/initialization/index.md","filePath":"supermemoryai/opencode-supermemory/start/initialization/index.md"}'),n={name:"supermemoryai/opencode-supermemory/start/initialization/index.md"};function s(r,e,l,c,d,p){return i(),o("div",null,[...e[0]||(e[0]=[a(`<h1 id="project-initialization-making-a-first-impression" tabindex="-1">Project Initialization: Making a First Impression <a class="header-anchor" href="#project-initialization-making-a-first-impression" aria-label="Permalink to &quot;Project Initialization: Making a First Impression&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li><strong>One-Click Familiarity</strong>: Enable the Agent to actively explore and understand the entire codebase like a new employee.</li><li><strong>Build Long-Term Memory</strong>: Automatically extract project technology stack, architectural patterns, and coding conventions into Supermemory.</li><li><strong>Eliminate Repetitive Explanations</strong>: Never repeat &quot;We use Bun&quot; or &quot;All components must have tests&quot; at the start of every session again.</li></ul><h2 id="the-current-dilemma" tabindex="-1">The Current Dilemma <a class="header-anchor" href="#the-current-dilemma" aria-label="Permalink to &quot;The Current Dilemma&quot;">​</a></h2><p>Have you encountered these situations?</p><ul><li><strong>Repetitive Labor</strong>: Spending significant effort explaining basic project details every time you start a new session.</li><li><strong>Context Amnesia</strong>: The Agent frequently forgets specific directory structures, creating files in the wrong locations.</li><li><strong>Inconsistent Standards</strong>: The Agent&#39;s coding style fluctuates, switching between <code>interface</code> and <code>type</code> randomly.</li></ul><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><ul><li><strong>Immediately After Installation</strong>: This is the first step in using opencode-supermemory.</li><li><strong>Taking Over a New Project</strong>: Quickly establish a memory bank for the project.</li><li><strong>After Major Refactoring</strong>: When the project architecture changes and the Agent&#39;s knowledge needs updating.</li></ul><h2 id="🎒-preparation" tabindex="-1">🎒 Preparation <a class="header-anchor" href="#🎒-preparation" aria-label="Permalink to &quot;🎒 Preparation&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prerequisite Check</p><p>Please ensure you have completed the installation and configuration steps in <a href="./../getting-started/">Getting Started</a>, and that your <code>SUPERMEMORY_API_KEY</code> is correctly set.</p></div><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>The <code>/supermemory-init</code> command is not essentially a binary program, but a <strong>carefully crafted Prompt</strong>.</p><p>When you run this command, it sends a detailed &quot;onboarding guide&quot; to the Agent, instructing it to:</p><ol><li><strong>Deep Research</strong>: Actively read <code>README.md</code>, <code>package.json</code>, Git commit history, etc.</li><li><strong>Structured Analysis</strong>: Identify the project&#39;s technology stack, architectural patterns, and implicit conventions.</li><li><strong>Persistent Storage</strong>: Use the <code>supermemory</code> tool to save these insights into the cloud database.</li></ol><div class="info custom-block"><p class="custom-block-title">Memory Scopes</p><p>The initialization process distinguishes between two types of memory:</p><ul><li><strong>Project Scope</strong>: Applies only to the current project (e.g., build commands, directory structure).</li><li><strong>User Scope</strong>: Applies to all your projects (e.g., your preferred coding style).</li></ul></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-run-the-initialization-command" tabindex="-1">Step 1: Run the Initialization Command <a class="header-anchor" href="#step-1-run-the-initialization-command" aria-label="Permalink to &quot;Step 1: Run the Initialization Command&quot;">​</a></h3><p>In the OpenCode input box, enter the following command and send:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/supermemory-init</span></span></code></pre></div><p><strong>Why</strong> This loads the predefined Prompt, triggering the Agent&#39;s exploration mode.</p><p><strong>What You Should See</strong> The Agent will reply, indicating it understands the task and is planning the research steps. It might say: &quot;I will start by exploring the codebase structure and configuration files...&quot;</p><h3 id="step-2-observe-the-exploration-process" tabindex="-1">Step 2: Observe the Exploration Process <a class="header-anchor" href="#step-2-observe-the-exploration-process" aria-label="Permalink to &quot;Step 2: Observe the Exploration Process&quot;">​</a></h3><p>The Agent will automatically execute a series of operations; you just need to watch. It typically will:</p><ol><li><strong>Read Config Files</strong>: Read <code>package.json</code>, <code>tsconfig.json</code>, etc., to understand the tech stack.</li><li><strong>Check Git History</strong>: Run <code>git log</code> to understand commit conventions and active contributors.</li><li><strong>Explore Directory Structure</strong>: Use <code>ls</code> or <code>list_files</code> to view the project layout.</li></ol><p><strong>Example Output</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Agent] Reading package.json to identify dependencies...</span></span>
<span class="line"><span>[Agent] Running git log to understand commit conventions...</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Consumption Note</p><p>This process is a deep investigation and may consume a significant number of Tokens (usually involving 50+ tool calls). Please be patient until the Agent reports completion.</p></div><h3 id="step-3-verify-generated-memories" tabindex="-1">Step 3: Verify Generated Memories <a class="header-anchor" href="#step-3-verify-generated-memories" aria-label="Permalink to &quot;Step 3: Verify Generated Memories&quot;">​</a></h3><p>When the Agent indicates initialization is complete, you can check what it has actually remembered. Enter:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> List</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memories</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> for</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> current</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> project</span></span></code></pre></div><p>Or call the tool directly (if you want to see raw data):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>supermemory(mode: &quot;list&quot;, scope: &quot;project&quot;)</span></span></code></pre></div><p><strong>What You Should See</strong> The Agent lists a series of structured memories, for example:</p><table tabindex="0"><thead><tr><th>Type</th><th>Example Content</th></tr></thead><tbody><tr><td><code>project-config</code></td><td>&quot;Uses Bun runtime. Build command: bun run build&quot;</td></tr><tr><td><code>architecture</code></td><td>&quot;API routes are located in src/routes/, using Hono framework&quot;</td></tr><tr><td><code>preference</code></td><td>&quot;Strict TypeScript usage: no &#39;any&#39; type allowed&quot;</td></tr></tbody></table><h3 id="step-4-fill-in-gaps-optional" tabindex="-1">Step 4: Fill in Gaps (Optional) <a class="header-anchor" href="#step-4-fill-in-gaps-optional" aria-label="Permalink to &quot;Step 4: Fill in Gaps (Optional)&quot;">​</a></h3><p>If the Agent missed key information (like a special rule that is only a verbal agreement), you can manually add it:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Please remember: In this project, all date handling must use the dayjs library; native Date is prohibited.</span></span></code></pre></div><p><strong>What You Should See</strong> The Agent replies with confirmation and calls <code>supermemory(mode: &quot;add&quot;)</code> to save this new rule.</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><ul><li>[ ] Did the Agent automatically execute exploration tasks after running <code>/supermemory-init</code>?</li><li>[ ] Can you view the newly generated memories using the <code>list</code> command?</li><li>[ ] Do the memory contents accurately reflect the actual state of the current project?</li></ul><h2 id="pitfalls-to-avoid" tabindex="-1">Pitfalls to Avoid <a class="header-anchor" href="#pitfalls-to-avoid" aria-label="Permalink to &quot;Pitfalls to Avoid&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Do Not Run Frequently</p><p>Initialization is a time-consuming and Token-intensive process. Usually, it only needs to be run once per project. Re-run only when the project undergoes significant changes.</p></div><div class="danger custom-block"><p class="custom-block-title">Privacy Notice</p><p>Although the plugin automatically sanitizes content in <code>&lt;private&gt;</code> tags, the Agent reads a large number of files during initialization. Please ensure your codebase does not contain hardcoded sensitive keys (like AWS Secret Keys), otherwise, they might be stored in memory as &quot;project configuration&quot;.</p></div><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Through <code>/supermemory-init</code>, we have completed the transformation from &quot;stranger&quot; to &quot;skilled worker&quot;. Now, the Agent has memorized the project&#39;s core architecture and conventions. In subsequent coding tasks, it will automatically utilize this context to provide you with more precise assistance.</p><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><blockquote><p>Next, we will learn about the <strong><a href="./../../core/context-injection/">Automatic Context Injection Mechanism</a></strong>.</p><p>You will learn:</p><ul><li>How the Agent &quot;remembers&quot; these memories at the start of a session.</li><li>How to trigger specific memory recall via keywords.</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source location</strong></summary><blockquote><p>Last Updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>Initialization Prompt Definition</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/cli.ts#L13-L163" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>13-163</td></tr><tr><td>Memory Tool Implementation</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L183-L485" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>183-485</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>SUPERMEMORY_INIT_COMMAND</code>: Defines the specific Prompt content for the <code>/supermemory-init</code> command, guiding the Agent on how to conduct research and memorization.</li></ul></details>`,50)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
